import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'app_colors.dart';import 'app_spacing.dart';import 'app_typography.dart';class DsListItem extends StatefulWidget {  final Widget leading;  final String title;  final String subtitle;  final String trailingText;  final Color? trailingTextColor;  final VoidCallback? onTap;  const DsListItem({    super.key,    required this.leading,    required this.title,    required this.subtitle,    required this.trailingText,    this.trailingTextColor,    this.onTap,  });  @override  State<DsListItem> createState() => _DsListItemState();}@overrideclass _DsListItemState extends State<DsListItem> with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<Color?> _highlightAnimation;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 150),    );    _highlightAnimation = ColorTween(      begin: AppColors.background,      end: AppColors.surface.withOpacity(0.5),    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _onTapDown(TapDownDetails details) {    HapticFeedback.lightImpact();    _controller.forward();  }  void _onTapUp(TapUpDetails details) {    _controller.reverse();  }  void _onTapCancel() {    _controller.reverse();  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTapDown: widget.onTap != null ? _onTapDown : null,      onTapUp: widget.onTap != null ? _onTapUp : null,      onTapCancel: widget.onTap != null ? _onTapCancel : null,      onTap: widget.onTap,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Container(            height: AppSpacing.listItemHeight,            color: _highlightAnimation.value,            padding: const EdgeInsets.symmetric(horizontal: AppSpacing.paddingLarge),            child: Column(              children: [                Expanded(                  child: Row(                    children: [                      widget.leading,                      SizedBox(width: AppSpacing.paddingMedium),                      Expanded(                        child: Column(                          crossAxisAlignment: CrossAxisAlignment.start,                          mainAxisAlignment: MainAxisAlignment.center,                          children: [                            Text(                              widget.title,                              style: AppTypography.listItemPrimary,                              maxLines: 1,                              overflow: TextOverflow.ellipsis,                            ),                            SizedBox(height: AppSpacing.gridBase / 2),                            Text(                              widget.subtitle,                              style: AppTypography.listItemSecondary,                              maxLines: 1,                              overflow: TextOverflow.ellipsis,                            ),                          ],                        ),                      ),                      SizedBox(width: AppSpacing.paddingMedium),                      Text(                        widget.trailingText,                        style: AppTypography.listItemAmount.copyWith(                          color: widget.trailingTextColor ?? AppColors.textPrimary,                        ),                      ),                    ],                  ),                ),                Divider(height: 1, thickness: 1, color: AppColors.divider),              ],            ),          );        },      ),    );  }}